**C++ Code:**

`#include &lt;iostream&gt;
#include &lt;vector&gt;
#include &lt;algorithm&gt;
#include &lt;deque&gt;
using namespace std;

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int N;
    cin &gt;&gt; N;
    vector&lt;pair&lt;int,int&gt;&gt; sir(N), nav(N);
    for (int i = 0; i &lt; N; i++){
        int x;
        cin &gt;&gt; x;
        sir[i] = {x, i};
    }
    for (int i = 0; i &lt; N; i++){
        int x;
        cin &gt;&gt; x;
        nav[i] = {x, i};
    }

    sort(sir.begin(), sir.end());
    sort(nav.begin(), nav.end());

    deque&lt;pair&lt;int,int&gt;&gt; dq;
    for(auto &amp;p: nav)
        dq.push_back(p);

    vector&lt;int&gt; ans(N, -1);
    int wins = 0;
    for(auto &amp;player: sir){
        if(player.first &gt; dq.front().first){
            ans[player.second] = dq.front().second;
            dq.pop_front();
            wins++;
        }
        else{
            ans[player.second] = dq.back().second;
            dq.pop_back();
        }
    }

    cout &lt;&lt; wins &lt;&lt; "\n";
    for (int i = 0; i &lt; N; i++){
        cout &lt;&lt; ans[i] + 1 &lt;&lt; "\n";
    }

    return 0;
}
