`def main():
    import sys, bisect
    data = sys.stdin.read().split()
    if not data:
        return
    N = int(data[0])
    sir = []
    nav = []
    idx = 1
    for i in range(N):
        sir.append((int(data[idx]), i))
        idx += 1
    for i in range(N):
        nav.append((int(data[idx]), i))
        idx += 1

    sir.sort()
    nav.sort()
    ans = [-1] * N
    wins = 0
    list_nav = nav[:]  # using a list as our sorted container

    for rating, sIdx in sir:
        pos = bisect.bisect_left(list_nav, (rating, -1))
        if pos &gt; 0:
            candidate = list_nav[pos - 1]
            wins += 1
            ans[sIdx] = candidate[1]
            del list_nav[pos - 1]
        else:
            candidate = list_nav[-1]
            ans[sIdx] = candidate[1]
            del list_nav[-1]

    output = [str(wins)]
    for x in ans:
        output.append(str(x + 1))
    sys.stdout.write("\n".join(output))

if __name__ == "__main__":
